SELECT bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state, bs.applicability, up.applicability AS applicability_1 FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs JOIN comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS up ON bs.bldg_id = up.bldg_id AND bs."in.nhgis_tract_gisjoin" = up."in.nhgis_tract_gisjoin" AND bs.state = up.state AND bs.upgrade = 0 WHERE bs.applicability = true AND up.applicability = true AND up.upgrade = 1 AND (bs."out.electricity.total.energy_consumption..kwh" - up."out.electricity.total.energy_consumption..kwh" >= 0.001 OR bs."out.natural_gas.total.energy_consumption..kwh" - up."out.natural_gas.total.energy_consumption..kwh" >= 0.001 OR bs."out.other_fuel.total.energy_consumption..kwh" - up."out.other_fuel.total.energy_consumption..kwh" >= 0.001 OR bs."out.district_cooling.total.energy_consumption..kwh" - up."out.district_cooling.total.energy_consumption..kwh" >= 0.001 OR bs."out.district_heating.total.energy_consumption..kwh" - up."out.district_heating.total.energy_consumption..kwh" >= 0.001)